// Univariate equation-solving benchmark runner.
//
// Reads benchmarks/audit/solve_cases.json (generated by gen_solve.py from
// SymPy's test_solveset.py), runs three configurations —
//   • CE        : base engine, no opt-in libraries
//   • CE+Fungrim: loadIdentities(ce, { solve: true }) — the solve templates
//   • SymPy     : its `solve()` outcome, precomputed at gen time
// — and grades each by a residual-substitution oracle:
//
//   sound      every returned real root r has |residual(r)| < TOL
//   complete   (finite sets only) the sound roots cover the reference set
//
//   correct  = sound + complete         🟡 partial = sound, missing roots
//   wrong    = a returned root fails     ∅ unsolved = none returned
//
// Cardinality (from solveset) decides how completeness is judged: `infinite`
// (periodic trig) sets ask only for ≥1 sound root; `empty` asks for none.
//
// Run:  npx tsx benchmarks/audit/solve.ts

import { execFileSync } from 'node:child_process';
import { readFileSync, writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';
import { tmpdir } from 'node:os';
// Import the MINIFIED production bundles, not `src/`, so live `console.assert`
// (~2× overhead on the symbolic engine) is stripped and CE timings reflect
// shipped code. Requires `npm run build production` first. See
// PERFORMANCE_FINDINGS.md P0-2.
import { ComputeEngine } from '../../dist/compute-engine.min.esm.js';
import { loadIdentities } from '../../dist/identities.min.esm.js';
import { mathJsonToWL } from '../runners/mathjson-to-wl.mjs';

const __dirname = dirname(fileURLToPath(import.meta.url));
const TOL = 1e-6;
const NODE = process.execPath;
const WOLFRAM_BATCH = join(__dirname, '..', 'runners', 'run_wolfram_batch.mjs');

type Card = 'finite' | 'infinite' | 'empty';
interface Case {
  id: string;
  cat: string;
  title: string;
  ce: { op: string; var: string; mathjson: any };
  sympy: { expr: string; result: { status: string; roots: string[] } };
  verify: { kind: string; cardinality: Card; roots: string[] };
}
type Verdict = 'correct' | 'partial' | 'wrong' | 'unsolved' | 'error';

const cases: Case[] = JSON.parse(
  readFileSync(join(__dirname, 'solve_cases.json'), 'utf8')
);

const ceBase = new ComputeEngine();
const ceRF = new ComputeEngine();
loadIdentities(ceRF, { solve: true });

const realOf = (b: any): number | null => {
  try {
    const r = b.N();
    const v = typeof r.re === 'number' ? r.re : Number(r.toString());
    if (!isFinite(v)) return null;
    const im = typeof r.im === 'number' ? r.im : 0;
    return Math.abs(im) > 1e-9 ? null : v;
  } catch {
    return null;
  }
};

const covers = (got: number[], ref: number[]) =>
  ref.every((r) => got.some((g) => Math.abs(g - r) <= 1e-6 * (1 + Math.abs(r))));

/** Run one engine on one case and grade it. */
function runCE(engine: ComputeEngine, c: Case): { v: Verdict; note?: string } {
  let roots: any[] | null;
  try {
    roots = engine.expr(c.ce.mathjson).solve(c.ce.var);
  } catch (e: any) {
    return { v: 'error', note: e?.message };
  }
  roots = roots || [];
  const resid = engine.expr(c.ce.mathjson);

  // Keep real roots; check each is sound by substitution.
  const sound: number[] = [];
  let badReal = 0;
  for (const root of roots) {
    const rv = realOf(root);
    if (rv === null) continue; // complex / unevaluable root — ignore for real grading
    let res: number | null = null;
    try {
      res = realOf(resid.subs({ [c.ce.var]: root }));
    } catch {
      res = null;
    }
    if (res !== null && Math.abs(res) < TOL) sound.push(rv);
    else badReal++;
  }
  return judge(c, roots.length, sound, badReal);
}

/** Grade SymPy's precomputed outcome the same way (its roots are real numeric,
 *  sourced from solve()/mpmath — trusted sound). */
function runSymPy(c: Case): { v: Verdict } {
  const r = c.sympy.result;
  if (r.status !== 'ok' || r.roots.length === 0)
    return { v: c.verify.cardinality === 'empty' ? 'correct' : 'unsolved' };
  const got = r.roots.map(Number);
  return judge(c, got.length, got, 0);
}

// --- Wolfram / Mathematica (the reference baseline) ------------------------
// One `wolframscript` kernel solves every case (`Solve[expr == 0, x]`), via the
// shared batch runner. Each case's `ce` MathJSON becomes the Wolfram residual;
// the runner returns the real roots and the |residual| at each, so we grade
// soundness ourselves (like CE) rather than trusting the roots blind.
function runWolframAll(): Record<string, any> {
  const by: Record<string, any> = {};
  const tasks = cases.map((c) => {
    try {
      return { id: c.id, op: 'solve', expr: mathJsonToWL(c.ce.mathjson), var: c.ce.var, points: [] };
    } catch (e: any) {
      by[c.id] = { status: 'error', error: String(e?.message ?? e).slice(0, 120) };
      return null;
    }
  }).filter(Boolean);
  if (!tasks.length) return by;
  const tmp = join(tmpdir(), `solve-wl-${process.pid}.json`);
  writeFileSync(tmp, JSON.stringify({ real: false, tasks }));
  try {
    const out = execFileSync(NODE, [WOLFRAM_BATCH, tmp], { encoding: 'utf8', timeout: 1800000, maxBuffer: 64 * 1024 * 1024 });
    for (const line of out.trim().split('\n')) { try { const o = JSON.parse(line); if (o.id) by[o.id] = o; } catch {} }
  } catch (e: any) { console.error('wolfram failed:', (e.message || e).toString().split('\n')[0]); }
  return by;
}

/** Grade a Wolfram batch result with the same soundness+completeness oracle as
 *  CE: a returned real root is sound iff |residual| < TOL. */
function gradeWolfram(c: Case, res: any): { v: Verdict; note?: string } {
  if (!res || res.status === 'error') return { v: 'error', note: res?.error };
  if (res.status === 'timeout') return { v: 'error', note: 'timeout' };
  const roots: any[] = res.roots || [];
  const mags: any[] = res.values || [];
  if (res.status !== 'ok' || roots.length === 0)
    return { v: c.verify.cardinality === 'empty' ? 'correct' : 'unsolved' };
  const sound: number[] = [];
  let badReal = 0;
  for (let i = 0; i < roots.length; i++) {
    const rv = Number(roots[i]);
    if (!isFinite(rv)) continue;
    const m = Number(mags[i]);
    if (isFinite(m) && m < TOL) sound.push(rv);
    else badReal++;
  }
  return judge(c, roots.length, sound, badReal);
}

function judge(
  c: Case,
  returned: number,
  sound: number[],
  badReal: number
): { v: Verdict; note?: string } {
  const ref = c.verify.roots.map(Number);
  if (returned === 0)
    return { v: c.verify.cardinality === 'empty' ? 'correct' : 'unsolved' };
  if (badReal > 0) return { v: 'wrong', note: `${badReal} bad root(s)` };
  if (sound.length === 0) return { v: 'unsolved' };
  if (c.verify.cardinality === 'empty') return { v: 'wrong' };
  if (c.verify.cardinality === 'infinite') return { v: 'correct' }; // ≥1 sound root
  // finite: completeness vs the reference set
  return covers(sound, ref)
    ? { v: 'correct' }
    : { v: 'partial', note: `${sound.length}/${ref.length} roots` };
}

// --- run -------------------------------------------------------------------
const SYM: Record<Verdict, string> = {
  correct: '✅',
  partial: '🟡',
  wrong: '❌',
  unsolved: '∅',
  error: '⚠️',
};

const wolframById = runWolframAll();
const rows = cases.map((c) => ({
  c,
  ce: runCE(ceBase, c),
  rf: runCE(ceRF, c),
  sy: runSymPy(c),
  wo: gradeWolfram(c, wolframById[c.id]),
}));

// Per-category + overall tallies (count "correct" only).
const cats = [...new Set(cases.map((c) => c.cat))];
const tally = (sel: (r: (typeof rows)[number]) => Verdict, pred: (c: Case) => boolean) =>
  rows.filter((r) => pred(r.c) && sel(r) === 'correct').length;

const md: string[] = [];
md.push('# Univariate Equation-Solving Benchmark', '');
md.push(
  '_Runner: **minified production bundles** (`dist/*.min.esm.js`, `console.assert` stripped) — CE times reflect ' +
    'shipped code. Rebuild with `npm run build production` before running._',
  '',
);
md.push(
  'Adapted from SymPy’s `test_solveset.py` (univariate cases). Each returned ' +
    'root is graded **sound** by substitution (`|residual| < 1e-6`); `finite` ' +
    'solution sets must also be **complete** (cover the reference set), while ' +
    '`infinite` (periodic trig) sets ask only for one sound root. SymPy’s ' +
    'column is its `solve()` outcome; **Mathematica** (the reference baseline) ' +
    'runs `Solve[expr == 0, x]` live via `wolframscript`, graded by the same oracle.',
  ''
);
md.push(
  '**✅ correct · 🟡 partial (sound but incomplete) · ❌ wrong · ∅ not solved · ⚠️ runtime error**',
  ''
);

// Summary table
md.push('| Category | n | CE | CE+Fungrim | SymPy | Mathematica |', '|---|--:|--:|--:|--:|--:|');
for (const cat of cats) {
  const n = cases.filter((c) => c.cat === cat).length;
  md.push(
    `| ${cat} | ${n} | ${tally((r) => r.ce.v, (c) => c.cat === cat)} | ` +
      `${tally((r) => r.rf.v, (c) => c.cat === cat)} | ` +
      `${tally((r) => r.sy.v, (c) => c.cat === cat)} | ` +
      `${tally((r) => r.wo.v, (c) => c.cat === cat)} |`
  );
}
md.push(
  `| **all** | **${cases.length}** | ` +
    `**${tally((r) => r.ce.v, () => true)}** | ` +
    `**${tally((r) => r.rf.v, () => true)}** | ` +
    `**${tally((r) => r.sy.v, () => true)}** | ` +
    `**${tally((r) => r.wo.v, () => true)}** |`,
  ''
);

// Per-case detail
md.push('## Cases', '');
md.push('| id | equation | set | CE | CE+F | SymPy | Mathematica |', '|---|---|---|:-:|:-:|:-:|:-:|');
for (const { c, ce, rf, sy, wo } of rows) {
  const note = (x: { v: Verdict; note?: string }) =>
    SYM[x.v] + (x.note ? ` _(${x.note})_` : '');
  md.push(
    `| ${c.id} | ${c.title} | ${c.verify.cardinality} | ` +
      `${note(ce)} | ${note(rf)} | ${SYM[sy.v]} | ${note(wo)} |`
  );
}
md.push('');

writeFileSync(join(__dirname, 'REPORT-solve.md'), md.join('\n'));

const line = (label: string, sel: (r: (typeof rows)[number]) => Verdict) =>
  `${label.padEnd(12)} ${tally(sel, () => true)}/${cases.length} correct`;
console.error('Wrote benchmarks/audit/REPORT-solve.md (%d cases)', cases.length);
console.error(line('CE', (r) => r.ce.v));
console.error(line('CE+Fungrim', (r) => r.rf.v));
console.error(line('SymPy', (r) => r.sy.v));
console.error(line('Mathematica', (r) => r.wo.v));
